	('d3069971-b59e-47f8-8092-816c7b0281cf', '52cabb51-e88f-45cc-bb22-94c6b3a83cda', 'a65d515f-66b5-4765-a7d4-9bb446b69194', 'middle_school', '{"A": 8, "C": 2, "E": 4, "I": 4, "R": 2, "S": 6}', 'ASI', '{"verbal": {"total": 0, "correct": 0, "percentage": 0}, "spatial": {"total": 0, "correct": 0, "percentage": 0}, "abstract": {"total": 0, "correct": 0, "percentage": 0}, "clerical": {"total": 0, "correct": 0, "percentage": 0}, "numerical": {"total": 0, "correct": 0, "percentage": 0}}', 0.00, '{"A": 4, "C": 3.2, "E": 3.8, "N": 2.5, "O": 3.5, "workStyleSummary": "You''re open to new experiences, organized enough to get things done, enjoy social interaction, are highly creative, and handle stress well. This makes you adaptable and great in collaborative environments."}', NULL, NULL, NULL, 0.00, '{"score": 0, "weakTopics": ["No data"], "correctCount": 0, "strongTopics": ["No data"], "recommendation": "Focus on building domain expertise through projects and certifications.", "totalQuestions": 0}', '{"clusters": [{"fit": "High", "roles": {"mid": ["Digital Artist", "Game Designer", "Content Strategist", "Animation Artist"], "entry": ["Junior Graphic Designer", "Social Media Content Creator", "Camp Art Instructor", "Video Game Tester"]}, "title": "Creative Arts & Digital Media", "domains": ["Digital Media", "Entertainment", "Design", "Content Creation"], "evidence": {"aptitude": "Strong pattern recognition (75%) helps in design and storytelling", "interest": "High Artistic (A=8) and Social (S=6) scores show love for creative expression and teamwork", "personality": "High creativity, curiosity, and social enjoyment make you perfect for collaborative creative work"}, "examples": ["Digital Artist", "Game Designer", "Content Creator", "Music Producer", "Animator"], "whyItFits": "Your top RIASEC scores (Artistic and Social) show you love creating and working with others. Your pattern recognition strength helps you understand what makes designs and stories compelling. Your creativity and curiosity will help you generate fresh ideas.", "matchScore": 85, "description": "Your strong artistic interests (drawing, designing, writing) combined with your love for social interaction make this a perfect fit! You could create amazing digital art, design video games, or produce music that connects with people. Your pattern recognition skill helps you see how different creative elements work together.", "whatYoullDo": "Create visual art, design characters and worlds, write stories, produce music, or make videos that entertain and inspire people."}, {"fit": "Medium", "roles": {"mid": ["Art Teacher", "Drama Instructor", "Museum Educator", "Educational Program Coordinator"], "entry": ["Teaching Assistant", "Camp Counselor", "Library Helper", "Tutor"]}, "title": "Education & Creative Learning", "domains": ["Education", "Museums", "Community Centers", "Summer Programs"], "evidence": {"aptitude": "Verbal reasoning can develop through explaining concepts to others", "interest": "Social and Artistic interests align with teaching and mentoring", "personality": "Curiosity and love of learning make you passionate about sharing knowledge"}, "examples": ["Art Teacher", "Drama Coach", "Museum Educator", "After-School Program Leader"], "whyItFits": "Your Social (S=6) and Artistic (A=8) scores show you enjoy helping people and expressing ideas. Your love of learning means you''d enjoy sharing knowledge. Your verbal reasoning (33%) can grow through teaching.", "matchScore": 75, "description": "Your social nature and love for learning could make you an amazing educator who makes subjects come alive! You could teach art, drama, or even creative writing. Your ability to connect ideas to real life would help students understand complex topics in fun ways.", "whatYoullDo": "Plan creative lessons, guide students in projects, organize performances or exhibitions, and help others discover their talents."}, {"fit": "Explore", "roles": {"mid": ["Science Communicator", "Environmental Journalist", "Museum Curator", "Documentary Researcher"], "entry": ["Science Camp Leader", "Zoo Educator", "Nature Center Volunteer", "Junior Science Writer"]}, "title": "Science Communication & Environmental Storytelling", "domains": ["Environmental Science", "Museums", "Media & Journalism", "Conservation"], "evidence": {"aptitude": "Pattern recognition helps identify scientific patterns to explain", "interest": "Investigative interest in nature/space + Artistic creativity", "personality": "Curiosity about the world and desire to share discoveries"}, "examples": ["Science YouTuber", "Museum Exhibit Designer", "Wildlife Documentary Creator", "Environmental Educator"], "whyItFits": "Your Investigative (I=4) interest in nature/space combines with your Artistic (A=8) creativity. Your pattern recognition helps explain complex science simply. Your social nature helps you connect with audiences.", "matchScore": 65, "description": "This exciting field combines your interest in nature/space/animals with your creative and social skills! You could create educational videos about wildlife, design interactive museum exhibits about climate change, or write stories that make science fascinating. Your pattern recognition helps spot connections in nature.", "whatYoullDo": "Research interesting topics, create engaging content (videos, articles, exhibits) that teaches people about science and nature, and inspire others to care about the environment."}], "specificOptions": {"highFit": [{"name": "Digital Artist/Animator", "salary": {"max": 6, "min": 3}}, {"name": "Game Designer", "salary": {"max": 7, "min": 4}}, {"name": "Content Creator (YouTube/TikTok)", "salary": {"max": 8, "min": 2}}], "mediumFit": [{"name": "Art Teacher", "salary": {"max": 5, "min": 3}}, {"name": "Museum Educator", "salary": {"max": 5, "min": 3}}], "exploreLater": [{"name": "Science Communicator", "salary": {"max": 6, "min": 3}}, {"name": "Environmental Journalist", "salary": {"max": 5, "min": 3}}]}}', '{"priorityA": [{"skill": "Digital Art & Design Basics", "reason": "Your artistic interests are strong, and learning digital tools will help you bring your creative ideas to life for games, animations, or social media content.", "targetLevel": "Beginner", "currentLevel": "Starting"}, {"skill": "Storytelling & Communication", "reason": "Your social nature and verbal reasoning can grow through practice telling stories, whether in writing, videos, or presentations. This helps share your creative ideas with others.", "targetLevel": "Beginner", "currentLevel": "Starting"}], "priorityB": [{"skill": "Basic Project Planning", "reason": "Learning to break big creative projects into smaller steps will help you finish what you start and build a portfolio of work.", "targetLevel": "Beginner"}], "currentStrengths": ["Creative Thinking", "Pattern Recognition", "Collaboration"], "recommendedTrack": "Creative Exploration & Digital Skills"}', '{"exposure": {"resources": ["Books: ''Steal Like an Artist'' by Austin Kleon", "Websites: Scratch.mit.edu for coding games, Canva for design", "YouTube channels: Proko (art), Kurzgesagt (science stories)"], "activities": ["Visit art museums or galleries", "Attend school plays or concerts", "Join online creative communities for teens", "Participate in art or writing contests"], "certifications": ["Typing certification", "Basic computer skills badge", "Digital art tutorial completion certificates"]}, "projects": [{"steps": ["Step 1: Brainstorm character ideas and sketch rough versions", "Step 2: Choose your favorite design and refine it", "Step 3: Add color and details digitally or on paper", "Step 4: Write a short story about your character"], "title": "Create Your First Digital Character", "output": "A character sheet with drawings and a short story", "skills": ["Character design", "Basic digital art", "Creative writing"], "purpose": "Learn the basics of character creation used in games, animation, and comics", "timeline": "2-3 months", "difficulty": "Begi