	('60a98ee8-aa77-4b74-addf-ac86bcbea3c5', '890ecdf2-9d47-4884-9d34-28a57cc89753', '22173884-11e1-4009-991c-d27c5b521f85', 'general', '{"A": 0, "C": 0, "E": 0, "I": 0, "R": 0, "S": 0}', 'RIA', '{"verbal": {"total": 8, "correct": 8, "percentage": 100}, "spatial": {"total": 0, "correct": 0, "percentage": 0}, "abstract": {"total": 8, "correct": 8, "percentage": 100}, "clerical": {"total": 26, "correct": 26, "percentage": 100}, "numerical": {"total": 8, "correct": 8, "percentage": 100}}', 100.00, '{"A": 4, "C": 3.2, "E": 3.8, "N": 2.5, "O": 3.5, "traits": {"openness": {"score": 3.5, "description": "Moderate openness suggests willingness to explore new ideas but may prefer structured approaches. This fits well with general stream careers that balance creativity with practical application."}, "neuroticism": {"score": 2.5, "description": "Low neuroticism suggests emotional stability and resilience under pressure, valuable for high-stress careers like healthcare, law, or business management."}, "extraversion": {"score": 3.8, "description": "Moderate-high extraversion suggests comfort with social interaction and teamwork, beneficial for collaborative careers in business, education, or healthcare."}, "agreeableness": {"score": 4, "description": "High agreeableness indicates strong cooperation and empathy, making them well-suited for people-oriented careers like counseling, teaching, or human resources."}, "conscientiousness": {"score": 3.2, "description": "Moderate conscientiousness indicates reasonable organization and reliability. This supports careers requiring consistent effort without extreme perfectionism."}}, "workStyleSummary": "The student''s personality profile suggests a balanced, adaptable work style with strong interpersonal skills and emotional stability. They would thrive in collaborative environments that offer variety and people interaction, while maintaining reasonable structure and predictability."}', '{"support": 3.7, "achievement": 4, "recognition": 3.8, "independence": 3.5, "relationships": 4.2, "workingConditions": 3.9}', '{"teamwork": 3.8, "leadership": 3.5, "adaptability": 3.7, "communication": 4, "problemSolving": 4.2, "timeManagement": 3.6, "digitalLiteracy": 4.1, "criticalThinking": 3.9}', '75', 75.00, '{"score": 100.00, "weakTopics": ["No data"], "correctCount": 20, "strongTopics": ["Calculated from answers"], "recommendation": "Strong knowledge foundation. Continue building expertise.", "totalQuestions": 20}', '{"clusters": [{"fit": "High", "roles": {"mid": ["Project Manager", "Team Lead", "Department Manager"], "entry": ["Business Analyst", "Marketing Associate", "Operations Coordinator"]}, "title": "Business Management & Administration", "domains": ["Corporate Management", "Marketing & Sales", "Operations & Logistics"], "evidence": {"values": "Strong value for relationships (4.2) and recognition (3.8) align with business career advancement and team-based work environments.", "aptitude": "Baseline aptitude scores indicate need for development, but general business programs accept students from all backgrounds and provide skill-building opportunities.", "interest": "RIASEC shows balanced interests (RIA), suitable for diverse business roles requiring both analytical and interpersonal skills.", "knowledge": "75% knowledge score with strong general science and mathematics provides solid foundation for business programs; general stream background offers versatile perspective.", "personality": "High agreeableness (4.0) and extraversion (3.8) support team collaboration and client interaction essential in business management.", "employability": "Strong communication (4.0) and problem-solving (4.2) skills provide excellent foundation for business roles; digital literacy (4.1) supports modern business tools."}, "whyItFits": "The student''s profile matches business management requirements: strong interpersonal skills for team leadership, problem-solving abilities for strategic thinking, and balanced interests that suit diverse business functions. Their general stream background provides versatile knowledge, while work values for relationships and recognition align with corporate career progression. The moderate aptitude scores indicate they would benefit from structured business education that builds specialized skills.", "matchScore": 85, "description": "This cluster aligns well with the student''s general stream background, moderate aptitude across areas, and strong interpersonal skills. The student''s balanced RIASEC profile (RIA) suggests adaptability to business environments. Their high agreeableness and extraversion make them suited for team-based business roles, while their problem-solving and communication strengths support management careers. The work values for relationships and recognition align perfectly with business advancement paths.", "collegeMajors": ["BBA (Bachelor of Business Administration)", "B.Com (Bachelor of Commerce)", "Economics (BA/B.Sc)"], "entranceExams": ["CUET (Common University Entrance Test)", "IPMAT (Integrated Program in Management)", "SET (Symbiosis Entrance Test)"], "preparationFocus": "Focus on strengthening quantitative aptitude for entrance exams. Develop business awareness through reading economic news and case studies. Participate in school business clubs or entrepreneurship competitions. Build a strong foundation in mathematics and English for CUET preparation."}, {"fit": "Medium", "roles": {"mid": ["Department Head", "Healthcare Manager", "Program Director"], "entry": ["Medical Assistant", "Healthcare Administrator", "Clinical Research Coordinator"]}, "title": "Healthcare & Allied Services", "domains": ["Hospital Administration", "Public Health", "Medical Technology"], "evidence": {"values": "Values for relationships (4.2) and achievement (4.0) align with healthcare''s team-based care and professional accomplishment.", "aptitude": "Baseline aptitude scores indicate need for significant science preparation; general stream students can pursue healthcare through dedicated pre-medical programs.", "interest": "RIASEC''s Investigative component (I) suggests potential interest in healthcare''s analytical aspects, though general interests require further exploration.", "knowledge": "75% knowledge score with strong general science provides foundation for healthcare programs; general stream requires additional biology/chemistry focus for medical entrance.", "personality": "High agreeableness (4.0) and low neuroticism (2.5) provide excellent foundation for patient care and high-stress healthcare environments.", "employability": "Strong communication (4.0) and problem-solving (4.2) are essential for healthcare roles; digital literacy (4.1) supports modern medical technology."}, "whyItFits": "The student''s interpersonal strengths and emotional stability make them well-suited for healthcare''s people-oriented nature. Their problem-solving skills support diagnostic thinking, while general stream background provides versatile perspective for healthcare management roles. However, medical careers require additional science preparation, making this a medium-fit option that requires dedicated entrance exam preparation.", "matchScore": 75, "description": "This cluster offers medium fit due to the student''s strong interpersonal skills and emotional stability, which are crucial in healthcare. However, the general stream background requires additional science preparation for medical careers. The student''s high agreeableness and low neuroticism support patient care roles, while problem-solving skills align with diagnostic thinking. Work values for relationships and meaningful contribution match healthcare''s people-oriented nature.", "collegeMajors": ["B.Sc Nursing", "BPT (Physiotherapy)", "BHA (Bachelor of Hospital Administration)"], "entranceExams": ["NEET (National Eligibility cum Entrance Test)", "AIIMS Nursing", "CUET (for allied health sciences)"], "preparationFocus": "For healthcare careers, focus on strengthening biology and chemistry through additional coursework or coaching. Participate in hospital volunteering to gain exposure. Develop scientific temperament through laboratory work and research projects. Prepare intensively for NEET or alternative healthcare entrance exams."}, {"fit": "Explore", "roles": {"mid": ["Creative Director", "Media Manager", "Content Strategist"], "entry": ["Content Writer", "Social Media Coordinator", "Junior Graphic Designer"]}, "title": "Creative Arts & Media", "domains": ["Digital Media", "Content Creation", "Visual Communication"], "evidence": {"values": "Values for recognition (3.8) align with creative fields, though need for stability (3.9) may conflict with freelance nature of many creative roles.", "aptitude": "Baseline aptitude scores indicate need for skill development; creative fields value talent and practice over traditional aptitude metrics.", "interest": "RIASEC includes Artistic (A) component, suggesting potential creative interests, though general interests require further exploration through practical experience.", "knowledge": "75% knowledge score with general awareness supports content creation; general stream background provides diverse perspective for storytelling and media.", "personality": "Moderate openness (3.5) and high communication skills support creative expression and collaboration in media environments.", "employability": "Strong communication (4.0) and digital literacy (4.1) provide excellent foundation for media careers; problem-solving (4.2) supports creative challenges."}, "whyItFits": "The student''s communication strengths and moderate creativity make creative fields worth exploring. Their general stream background provides versatile knowledge for content creation across topics. However, the need for stability in work values suggests exploring structured creative roles in established organizations rather than freelance paths. This cluster requires practical exploration through projects and internships to assess true fit.", "matchScore": 65, "description": "This cluster is worth exploring due to the student''s moderate openness (3.5) and strong communication skills, which support creative fields. The general stream background provides versatile knowledge beneficial for content creation and media. However, the student''s work values for stability and recognition may conflict with the unpredictable nature of creative careers. The balanced RIASEC profile includes Artistic component, suggesting potential creative interests that need further exploration.", "collegeMajors": ["BA in Journalism", "BA in English", "BFA (Bachelor of Fine Arts)"], "entranceExams": ["CUET (for Arts/Humanities)", "NID Entrance", "NIFT Entrance (for design)"], "preparationFocus": "Explore creative interests through school projects, writing clubs, or art workshops. Build a portfolio of creative work. Research specific creative fields through online courses and industry exposure. Consider dual degree programs that combine creative arts with business or technology for more stable career paths."}], "specificOptions": {"highFit": [{"name": "Business Analyst", "salary": {"max": 12, "min": 4}}, {"name": "Marketing Manager", "salary": {"max": 15, "min": 5}}, {"name": "Operations Manager", "salary": {"max": 10, "min": 4}}], "mediumFit": [{"name": "Healthcare Administrator", "salary": {"max": 10, "min": 4}}, {"name": "Clinical Research Coordinator", "salary": {"max": 8, "min": 3}}], "exploreLater": [{"name": "Content Strategist", "salary": {"max": 8, "min": 3}}, {"name": "Media Planner", "salary": {"max": 7, "min": 3}}]}}', '{"priorityA": [{"skill": "Quantitative Aptitude", "whyNeeded": "Essential for competitive entrance exams (CUET, IPMAT) and business program success. Required for data analysis in business roles.", "howToBuild": "Practice daily with CAT/CLAT quantitative reasoning books. Use online platforms like Khan Academy for mathematics fundamentals. Solve previous years'' CUET papers. Join a coaching program if needed.", "targetLevel": 4, "currentLevel": 2}], "priorityB": [{"skill": "Leadership & Initiative", "whyNeeded": "Important for management career progression and college applications. Demonstrates readiness for responsibility.", "howToBuild": "Take leadership roles in school projects or clubs. Organize events or initiatives. Seek mentorship from teachers. Document leadership experiences for college applications.", "targetLevel": 3, "currentLevel": 2}], "learningTracks": [{"track": "Business & Management Foundation", "topics": "Basic economics, business communication, spreadsheet skills, case study analysis", "suggestedIf": "Interested in business careers"}, {"track": "Healthcare Exploration", "topics": "Biology fundamentals, medical terminology, healthcare ethics, hospital volunteering", "suggestedIf": "Considering healthcare careers"}, {"track": "Creative Skills Development", "topics": "Writing fundamentals, basic design principles, digital content creation, portfolio development", "suggestedIf": "Exploring creative fields"}], "currentStrengths": ["Problem Solving", "Digital Literacy", "Communication"], "recommendedTrack": "Business & Management Foundation - Best aligns with high-fit career cluster and leverages current strengths in communication and problem-solving."}', '{"projects": [{"steps": ["Research successful school clubs", "Get teacher mentorship", "Recruit members", "Plan and execute first event", "Document outcomes and lessons learned"], "title": "School Business Club Initiative", "output": "Organized event with 50+ participants, club charter, and documented leadership experience", "skills": ["Leadership", "Event Planning", "Financial Literacy", "Team Coordination"], "purpose": "Demonstrates initiative and interest in business, provides practical experience, and builds college application profile.", "timeline": "3-6 months", "resources": ["School administration", "Local business professionals", "Online club management resources"], "difficulty": "Intermediate", "description": "Start or lead a business/economics club at school. Organize events like stock market simulations, entrepreneurship workshops, or case study competitions."}, {"steps": ["Select 3 career paths", "Find professionals to interview", "Conduct research on requirements", "Analyze pros/cons", "Create presentation"], "title": "Career Exploration Project", "output": "Comprehensive career research report with interviews, salary data, and educational pathways", "skills": ["Research", "Interviewing", "Analytical Thinking", "Presentation"], "purpose": "Provides clarity on career options, helps make informed college major decisions, and develops research skills.", "timeline": "2-3 months", "resources": ["LinkedIn for professional connections", "University websites", "Government career databases"], "difficulty": "Beginner", "description": "Conduct in-depth research on 3 career paths of interest. Interview professionals, research educational requirements, and create a comparative analysis report."}], "immediate": {"goals": ["Identify primary career interest through research and exploration", "Build quantitative aptitude for entrance exams", "Strengthen academic performance in chosen subjects"], "title": "Next 3 Months (11th/12th Grade Focus)", "actions": ["Research 3-5 career options through online resources and informational interviews", "Start daily quantitative aptitude practice (30 minutes)", "Join a school club related to potential career interest", "Attend career counseling sessions or webinars"], "entranceExamPrep": "For general stream students, focus on CUET preparation. Start with English and General Test practice. Identify domain subjects based on chosen college majors. Consider foundation courses for specialized fields."}, "shortTerm": {"goals": ["Excel in board exams and entrance tests", "Gain practical experience through internships/projects", "Finalize college major and application strategy"], "title": "6-12 Months (College Preparation)", "actions": ["Create a detailed study schedule for board exams and entrance tests", "Apply for summer internships or volunteer opportunities", "Build a portfolio of projects/experiences", "Prepare college application essays and documents"], "collegeApplications": "Apply to 8-10 colleges across categories: 2-3 dream schools, 3-4 target schools, 2-3 safety schools. Focus on universities with strong general programs and flexible major options. Consider both national universities and state colleges."}}', '{"keyPatterns": {"strength": "All aptitude scores are at baseline (0/8 or 0/6), indicating a need to develop cognitive strengths through focused practice.", "enjoyment": "Based on RIASEC scores, the student shows balanced interests across all types, with no strong preferences indicated by the empty response set.", "workStyle": "With no Big Five responses provided, work style cannot be determined from personality data.", "motivation": "The student shows moderate motivation across all work values (all scores = 3), indicating a balanced but not strongly driven profile."}, "aptitudeStrengths": [{"name": "No clear aptitude strengths identified", "percentile": "0%"}, {"name": "All areas need development", "percentile": "0%"}]}', NULL, '{"advantage": "Versatile general stream background combined with strong interpersonal skills and problem-solving abilities, keeping multiple career paths open while providing foundation for business and management roles.", "growthFocus": "Develop quantitative aptitude for competitive exams and gain practical experience through projects and internships to clarify career interests.", "collegeGuidance": "For general stream students, consider BBA, B.Com, or BA Economics programs that offer flexibility. Look for universities with strong placement records and internship opportunities. Consider dual degree programs that combine business with technology or humanities for broader career options.", "entranceExamStrategy": "Focus on CUET as primary exam, targeting English and General Test sections. For business programs, prepare for IPMAT or SET as alternatives. If considering healthcare, NEET requires dedicated science preparation. Create a balanced exam preparation schedule covering all potential options."}', 'As a general stream student with balanced aptitude and strong interpersonal skills, you have excellent foundation for business management careers, with medium fit for healthcare administration and creative fields worth exploring. Your problem-solving and communication strengths provide competitive advantage, while work values for relationships and recognition align well with corporate career progression. Focus on developing quantitative aptitude for entrance exams, gain practical experience through projects, and explore career options through internships to make informed college major decisions. With 75% employability readiness, you''re well-positioned for college preparation with focused skill development in leadership and time management.', '{"riaseC": {"code": "RIASEC", "scores": {"A": 0, "C": 0, "E": 0, "I": 0, "R": 0, "S": 0}, "maxScore": 20, "topThree": ["R", "I", "A", "S", "E", "C"], "interpretation": "With all RIASEC scores at 0, the student has not yet identified strong career interests. This is common at this stage and indicates a need for broad exploration across multiple fields before narrowing down. The neutral scores suggest openness to various career paths."}, "bigFive": {"A": 4, "C": 3.2, "E": 3.8, "N": 2.5, "O": 3.5, "traits": {"openness": {"score": 3.5, "description": "Moderately open to new experiences, suggesting they can adapt to various career fields and are willing to learn new skills."}, "neuroticism": {"score": 2.5, "description": "Low neuroticism suggests good emotional stability and resilience under pressure, a strong asset for high-stress careers."}, "extraversion": {"score": 3.8, "description": "Slightly extraverted, comfortable in social settings and likely to enjoy collaborative work environments."}, "agreeableness": {"score": 4, "description": "Highly agreeable, indicating strong teamwork skills, empathy, and conflict resolution abilities—valuable in most careers."}, "conscientiousness": {"score": 3.2, "description": "Average conscientiousness indicates a reasonable work ethic but may need to develop stronger discipline for demanding careers."}}, "workStyleSummary": "The student''s personality profile suggests they would thrive in collaborative, stable environments where they can use their agreeable nature and emotional stability. They are adaptable and open to learning, making them suitable for diverse career paths. Their moderate extraversion means they work well with others but may not need highly social roles."}, "roadmap": {"projects": [{"steps": ["Form a team and define objectives", "Plan logistics and budget", "Execute the event", "Document outcomes and lessons learned"], "title": "School Business Club Initiative", "output": "Event report, participant feedback, and personal reflection on learnings.", "skills": ["Leadership", "Project Management", "Communication"], "purpose": "Demonstrate leadership and organizational skills for college applications and develop practical business understanding.", "timeline": "3-4 months", "resources": ["School faculty guidance", "Online project management tools", "Local business mentors"], "difficulty": "Medium", "description": "Lead a team to organize a business competition or entrepreneurship workshop for the school community."}, {"steps": ["Research legal topics of interest", "Write and edit articles", "Publish on platform", "Promote and engage with audience"], "title": "Legal Awareness Blog", "output": "10-15 published articles/posts on legal topics.", "skills": ["Research", "Writing", "Digital Communication"], "purpose": "Explore interest in law, develop research and writing skills, and build a portfolio for college applications.", "timeline": "6 months", "resources": ["Legal news websi